import React, { useState, useEffect } from 'react';
import { Link, useNavigate, useLocation } from 'react-router-dom';
import { ShoppingBag, User, Search, Menu, X, Heart, Settings } from 'lucide-react';

const Navbar = () => {
  const [isScrolled, setIsScrolled] = useState(false);
  const [mobileMenuOpen, setMobileMenuOpen] = useState(false);
  const location = useLocation();
  const navigate = useNavigate();

  useEffect(() => {
    const handleScroll = () => {
      setIsScrolled(window.scrollY > 20);
    };
    window.addEventListener('scroll', handleScroll);
    return () => window.removeEventListener('scroll', handleScroll);
  }, []);

  useEffect(() => {
    setMobileMenuOpen(false);
    document.body.style.overflow = 'unset';
  }, [location]);

  const toggleMobileMenu = () => {
    setMobileMenuOpen(!mobileMenuOpen);
    document.body.style.overflow = !mobileMenuOpen ? 'hidden' : 'unset';
  };

  return (
    <>
      <nav className={`fixed top-0 w-full z-[100] transition-all duration-500 ${
        isScrolled ? 'bg-white shadow-sleek py-1' : 'bg-white/90 backdrop-blur-md py-2 lg:py-3'
      }`}>
        <div className="container mx-auto px-4 lg:px-20 flex items-center justify-between">

          {/* Left: Menu Toggle + Logo */}
          <div className="flex items-center">
            <button 
              className="lg:hidden p-2 -ml-2 text-dark hover:text-primary transition-colors"
              onClick={toggleMobileMenu}
            >
              <Menu size={24} />
            </button>
            <Link to="/" className="text-xl lg:text-3xl font-black tracking-tighter text-dark ml-2 lg:ml-0 group">
              KAPDAKO<span className="text-primary group-hover:rotate-12 inline-block transition-transform">.</span>
            </Link>
          </div>

          {/* Center: Desktop Navigation */}
          <div className="hidden lg:flex items-center space-x-12 text-[11px] font-black text-dark uppercase tracking-[0.2em]">
            <Link to="/shop?category=Men" className="hover:text-primary transition-colors relative group">
               Men
               <span className="absolute -bottom-1 left-0 w-0 h-0.5 bg-primary group-hover:w-full transition-all duration-300"></span>
            </Link>
            <Link to="/shop?category=Women" className="hover:text-primary transition-colors relative group">
               Women
               <span className="absolute -bottom-1 left-0 w-0 h-0.5 bg-primary group-hover:w-full transition-all duration-300"></span>
            </Link>
            <Link to="/shop?category=Kids" className="hover:text-primary transition-colors relative group">
               Kids
               <span className="absolute -bottom-1 left-0 w-0 h-0.5 bg-primary group-hover:w-full transition-all duration-300"></span>
            </Link>
            <Link to="/shop?sale=true" className="text-primary hover:opacity-80 transition-colors relative group">
               Sale
               <span className="absolute -bottom-1 left-0 w-0 h-0.5 bg-primary group-hover:w-full transition-all duration-300"></span>
            </Link>
          </div>

          {/* Right: Search & Icons */}
          <div className="flex items-center space-x-1 lg:space-x-8">
            <button className="p-2 text-dark hover:text-primary transition-colors" onClick={() => navigate('/shop')}>
              <Search size={22} className="lg:w-5 lg:h-5" />
            </button>

            <Link to="/dashboard" className="hidden lg:flex flex-col items-center group text-dark hover:text-primary transition-all">
              <User size={20} className="mb-1" />
              <span className="text-[9px] font-black uppercase tracking-widest">Profile</span>
            </Link>

            <Link to="/wishlist" className="flex flex-col items-center group text-dark hover:text-primary transition-all">
              <Heart size={20} className="mb-1 lg:w-5 lg:h-5" />
              <span className="text-[9px] font-black uppercase tracking-widest hidden lg:block">Wishlist</span>
            </Link>

            <Link to="/cart" className="flex flex-col items-center group text-dark hover:text-primary transition-all relative">
              <ShoppingBag size={20} className="mb-1 lg:w-5 lg:h-5" />
              <span className="text-[9px] font-black uppercase tracking-widest hidden lg:block">Bag</span>
              <span className="absolute -top-1 -right-1 bg-dark text-white text-[8px] font-black w-4 h-4 flex items-center justify-center rounded-full leading-none group-hover:bg-primary transition-colors">
                2
              </span>
            </Link>
          </div>
        </div>
      </nav>

      {/* Modern Mobile Drawer */}
      <div className={`fixed inset-0 z-[1000] lg:hidden transition-all duration-500 ${mobileMenuOpen ? 'visible' : 'invisible'}`}>
        {/* Overlay */}
        <div className={`absolute inset-0 bg-dark/60 backdrop-blur-sm transition-opacity duration-500 ${mobileMenuOpen ? 'opacity-100' : 'opacity-0'}`} onClick={toggleMobileMenu}></div>

        {/* Panel */}
        <div className={`absolute left-0 top-0 bottom-0 w-[85%] max-w-[320px] bg-white transition-transform duration-500 ease-out flex flex-col ${mobileMenuOpen ? 'translate-x-0' : '-translate-x-full'}`}>
          <div className="p-6 flex justify-between items-center border-b border-surface">
            <span className="text-xl font-black tracking-tighter text-dark uppercase">KAPDAKO<span className="text-primary">.</span></span>
            <button onClick={toggleMobileMenu} className="p-2 bg-surface rounded-full text-dark"><X size={20} /></button>
          </div>

          <div className="flex-1 overflow-y-auto p-6 space-y-8">
             <div className="space-y-4">
                <span className="text-[10px] font-black uppercase tracking-[0.3em] text-light block mb-2">Shop Categories</span>
                {[
                  { name: 'Men', path: '/shop?category=Men' },
                  { name: 'Women', path: '/shop?category=Women' },
                  { name: 'Kids', path: '/shop?category=Kids' },
                  { name: 'New Arrivals', path: '/shop' },
                  { name: 'Sale', path: '/shop?sale=true', primary: true }
                ].map((link) => (
                  <Link 
                    key={link.name} 
                    to={link.path} 
                    className={`block text-lg font-black uppercase tracking-tight ${link.primary ? 'text-primary' : 'text-dark'}`}
                  >
                    {link.name}
                  </Link>
                ))}
             </div>

             <div className="pt-6 border-t border-surface space-y-5">
                {[
                  { icon: User, label: 'My Account', path: '/dashboard' },
                  { icon: ShoppingBag, label: 'My Orders', path: '/dashboard' },
                  { icon: Heart, label: 'My Wishlist', path: '/wishlist' },
                  { icon: Settings, label: 'Settings', path: '/dashboard' }
                ].map((item) => (
                  <Link key={item.label} to={item.path} className="flex items-center space-x-4 text-secondary hover:text-dark transition-colors">
                     <div className="w-10 h-10 bg-surface rounded-full flex items-center justify-center"><item.icon size={18} /></div>
                     <span className="text-sm font-bold uppercase tracking-widest">{item.label}</span>
                  </Link>
                ))}
             </div>
          </div>

          <div className="p-6 bg-surface">
             <Link to="/login" onClick={toggleMobileMenu} className="w-full btn-primary !rounded-xl !py-4 flex items-center justify-center font-black tracking-widest text-xs">
                LOGIN / REGISTER
             </Link>
          </div>
        </div>
      </div>

      {/* Spacer */}
      <div className="h-[56px] lg:h-[72px]"></div>
    </>
  );
};

export default Navbar;

import React from 'react';

const StatCard = ({ title, value, icon: Icon, trend, trendValue }) => {
  return (
    <div className="bg-white p-6 rounded-lg border border-gray-100 shadow-sm flex flex-col">
      <div className="flex justify-between items-start mb-4">
        <div>
          <p className="text-gray-500 text-sm font-medium uppercase tracking-wider mb-1">{title}</p>
          <h3 className="text-3xl font-heading font-bold text-gray-900">{value}</h3>
        </div>
        <div className="p-3 bg-gray-50 text-black rounded-lg">
          <Icon size={24} strokeWidth={2} />
        </div>
      </div>
      
      {trend && (
        <div className="mt-auto pt-4 border-t border-gray-50 flex items-center">
          <span className={`text-sm font-bold ${trend === 'up' ? 'text-green-500' : 'text-red-500'}`}>
            {trend === 'up' ? '↑' : '↓'} {trendValue}
          </span>
          <span className="text-gray-400 text-sm ml-2">vs last month</span>
        </div>
      )}
    </div>
  );
};

export default StatCard;

import React, { useState, useEffect } from 'react';
import { useParams, Link, useNavigate } from 'react-router-dom';
import { ShoppingBag, Heart, Star, Truck, RefreshCw, Ruler, ChevronRight, ChevronDown, Share2, ShieldCheck, ArrowLeft } from 'lucide-react';
import { toast } from 'react-toastify';

const MOCK_PRODUCT = { 
  _id: '1', 
  name: 'Premium Heavyweight Cotton Oversized Tee', 
  brand: 'LANDLO', 
  images: [
    'https://images.unsplash.com/photo-1521572163474-6864f9cf17ab?auto=format&fit=crop&q=80&w=1200',
    'https://images.unsplash.com/photo-1583743814966-8936f5b7be1a?auto=format&fit=crop&q=80&w=1200',
    'https://images.unsplash.com/photo-1576566588028-4147f3842f27?auto=format&fit=crop&q=80&w=1200',
    'https://images.unsplash.com/photo-1554568218-0f1715e72254?auto=format&fit=crop&q=80&w=1200',
  ], 
  price: 1499, 
  mrp: 2499,
  discount: 40,
  rating: 4.5, 
  numReviews: 1248, 
  description: 'Elevate your everyday rotation with our Premium Heavyweight Tee. Crafted from 240GSM organic cotton, this tee offers a structured silhouette with a soft-hand feel. Features a relaxed fit, dropped shoulders, and a durable ribbed crew neck.',
  sizes: ['S', 'M', 'L', 'XL', 'XXL'],
  colors: [
    { name: 'Pure White', hex: '#ffffff' },
    { name: 'Vintage Black', hex: '#222222' },
    { name: 'Classic Navy', hex: '#1E3A8A' },
  ],
  countInStock: 15
};

const ProductDetails = () => {
  const { id } = useParams();
  const navigate = useNavigate();
  const [activeImage, setActiveImage] = useState(0);
  const [selectedSize, setSelectedSize] = useState('M');
  const [expandedSection, setExpandedSection] = useState('description');
  const [isWishlisted, setIsWishlisted] = useState(false);

  const product = MOCK_PRODUCT; // Replace with API fetch later

  const handleAddToCart = () => {
    toast.success('Successfully added to Bag!');
  };

  const toggleWishlist = () => {
    setIsWishlisted(!isWishlisted);
    toast.success(isWishlisted ? 'Removed from Wishlist' : 'Added to Wishlist');
  };

  return (
    <div className="bg-white min-h-screen pb-32 lg:pb-20">
      {/* Header Navigation */}
      <div className="container mx-auto px-4 lg:px-20 py-4 lg:py-8">
        <div className="flex items-center justify-between">
           <div className="flex items-center space-x-2 text-[10px] font-black uppercase tracking-[0.2em] text-light">
             <Link to="/" className="hover:text-dark transition-colors">Home</Link>
             <ChevronRight size={10} />
             <Link to="/shop" className="hover:text-dark transition-colors">Clothing</Link>
             <ChevronRight size={10} className="hidden sm:block" />
             <span className="text-dark hidden sm:block truncate max-w-[150px]">{product.name}</span>
           </div>
           
           <button onClick={() => navigate(-1)} className="flex items-center text-[10px] font-black uppercase tracking-widest text-dark hover:text-primary transition-colors">
              <ArrowLeft size={14} className="mr-2" /> Back
           </button>
        </div>
      </div>

      <div className="container mx-auto lg:px-20">
        <div className="flex flex-col lg:flex-row lg:gap-20">
          
          {/* Left: Gallery Section */}
          <div className="w-full lg:w-[55%] flex flex-col-reverse lg:flex-row gap-4">
            {/* Desktop Thumbnails */}
            <div className="hidden lg:flex flex-col gap-4 w-20 shrink-0">
               {product.images.map((img, idx) => (
                 <button 
                  key={idx} 
                  onClick={() => setActiveImage(idx)}
                  className={`aspect-[3/4] overflow-hidden rounded-lg border-2 transition-all ${activeImage === idx ? 'border-primary shadow-lg' : 'border-transparent opacity-60 hover:opacity-100'}`}
                 >
                   <img src={img} alt="thumb" className="w-full h-full object-cover" />
                 </button>
               ))}
            </div>

            {/* Main Image View */}
            <div className="relative w-full aspect-[4/5] lg:aspect-[3/4] lg:rounded-3xl overflow-hidden bg-surface group">
               {/* Mobile Slider Indicator Overlay */}
               <div className="lg:hidden absolute top-4 left-4 z-10 bg-dark/60 backdrop-blur-md px-3 py-1 rounded-full text-[10px] font-black text-white tracking-widest">
                  {activeImage + 1} / {product.images.length}
               </div>

               {/* Mobile: Horizontal Scroll Snap Slider */}
               <div 
                className="lg:hidden flex overflow-x-auto snap-x snap-mandatory scroll-smooth no-scrollbar h-full w-full"
                onScroll={(e) => {
                  const slideWidth = e.currentTarget.offsetWidth;
                  const newIdx = Math.round(e.currentTarget.scrollLeft / slideWidth);
                  setActiveImage(newIdx);
                }}
               >
                  {product.images.map((img, idx) => (
                    <div key={idx} className="flex-shrink-0 w-full h-full snap-center">
                       <img src={img} alt={product.name} className="w-full h-full object-cover" />
                    </div>
                  ))}
               </div>

               {/* Desktop: Active Image */}
               <img 
                 src={product.images[activeImage]} 
                 alt={product.name} 
                 className="hidden lg:block w-full h-full object-cover transition-transform duration-1000 group-hover:scale-110" 
               />

               {/* Floating Actions */}
               <div className="absolute top-6 right-6 flex flex-col space-y-4 z-10">
                  <button 
                    onClick={toggleWishlist}
                    className={`w-12 h-12 rounded-full shadow-2xl backdrop-blur-md flex items-center justify-center transition-all duration-300 ${isWishlisted ? 'bg-primary text-white scale-110 shadow-primary/40' : 'bg-white/80 text-dark hover:bg-white'}`}
                  >
                    <Heart size={20} fill={isWishlisted ? 'currentColor' : 'none'} strokeWidth={isWishlisted ? 0 : 2} />
                  </button>
                  <button className="w-12 h-12 bg-white/80 text-dark rounded-full shadow-2xl backdrop-blur-md flex items-center justify-center hover:bg-white transition-all duration-300">
                    <Share2 size={20} />
                  </button>
               </div>

               {/* Mobile Dots */}
               <div className="lg:hidden absolute bottom-6 left-1/2 -translate-x-1/2 flex space-x-2">
                  {product.images.map((_, idx) => (
                    <div key={idx} className={`h-1.5 transition-all duration-300 rounded-full ${activeImage === idx ? 'w-8 bg-primary' : 'w-1.5 bg-white/50'}`}></div>
                  ))}
               </div>
            </div>
          </div>

          {/* Right: Product Info */}
          <div className="w-full lg:w-[45%] px-4 lg:px-0 py-10 lg:py-0">
            <div className="lg:sticky lg:top-32">
               <div className="mb-8">
                  <div className="flex items-center justify-between mb-4">
                     <span className="text-[10px] font-black uppercase tracking-[0.4em] text-primary bg-primary/5 px-4 py-1.5 rounded-full border border-primary/10">Summer Drop '26</span>
                     <div className="flex items-center space-x-1 bg-surface px-3 py-1.5 rounded-full">
                        <Star size={14} className="fill-yellow-500 text-yellow-500" />
                        <span className="text-xs font-black text-dark">4.8</span>
                        <span className="text-[10px] font-bold text-light lowercase tracking-wider">(1.2k)</span>
                     </div>
                  </div>
                  <h1 className="text-2xl lg:text-5xl font-black text-dark uppercase tracking-tight leading-[0.9] mb-4">
                    {product.name}
                  </h1>
                  <p className="text-secondary text-sm lg:text-lg font-medium tracking-wide mb-8 opacity-80 italic">
                    "Engineered for volume, refined for the modern silhouette."
                  </p>
                  
                  <div className="flex items-baseline space-x-6">
                    <span className="text-4xl lg:text-5xl font-black text-dark">Rs. {product.price}</span>
                    <span className="text-xl text-light line-through font-medium">Rs. {product.mrp}</span>
                    <span className="text-xl text-primary font-black animate-pulse">-{product.discount}%</span>
                  </div>
               </div>

               {/* Size Picker */}
               <div className="mb-12">
                  <div className="flex justify-between items-center mb-6">
                    <h3 className="text-[10px] font-black uppercase tracking-[0.3em] text-light">Select Size</h3>
                    <button className="flex items-center text-[10px] font-black text-primary uppercase tracking-widest hover:underline">
                      <Ruler size={14} className="mr-2" /> Size Guide
                    </button>
                  </div>
                  <div className="flex flex-wrap gap-4">
                    {product.sizes.map((size) => (
                      <button 
                        key={size}
                        onClick={() => setSelectedSize(size)}
                        className={`w-16 h-16 rounded-2xl border-2 font-black text-sm transition-all flex items-center justify-center ${
                          selectedSize === size 
                          ? 'border-dark bg-dark text-white shadow-xl -translate-y-1' 
                          : 'border-surface text-secondary hover:border-dark hover:text-dark bg-surface/50'
                        }`}
                      >
                        {size}
                      </button>
                    ))}
                  </div>
               </div>

               {/* Desktop CTA */}
               <div className="hidden lg:flex gap-4 mb-12">
                  <button 
                    onClick={handleAddToCart}
                    className="flex-1 btn-primary !rounded-2xl flex items-center justify-center space-x-4 py-6 shadow-2xl hover:shadow-primary/40 group active:scale-95 transition-all"
                  >
                    <ShoppingBag size={24} strokeWidth={3} className="group-hover:rotate-12 transition-transform" />
                    <span className="text-xl font-black tracking-widest uppercase">ADD TO BAG</span>
                  </button>
               </div>

               {/* Features Accordion */}
               <div className="space-y-4 border-t border-surface pt-10">
                  {[
                    { id: 'description', label: 'Artisanal Insights', content: product.description },
                    { id: 'specifications', label: 'Material & Care', content: 'Crafted from 100% GOTS certified organic cotton. Machine wash cold, line dry to preserve silhouette.' },
                    { id: 'delivery', label: 'Global Logistics', content: 'Standard: 3-5 days. Priority: 24 hours. Free global returns within 30 days.' }
                  ].map((section) => (
                    <div key={section.id} className="bg-surface/30 rounded-2xl overflow-hidden border border-border/50">
                       <button 
                        onClick={() => setExpandedSection(expandedSection === section.id ? '' : section.id)}
                        className="w-full px-6 py-5 flex justify-between items-center group"
                       >
                         <span className="text-[10px] font-black uppercase tracking-[0.2em] text-dark group-hover:text-primary transition-colors">{section.label}</span>
                         <ChevronDown size={16} className={`text-light transition-transform duration-500 ${expandedSection === section.id ? 'rotate-180 text-primary' : ''}`} />
                       </button>
                       <div className={`overflow-hidden transition-all duration-500 ease-in-out ${expandedSection === section.id ? 'max-h-64' : 'max-h-0'}`}>
                          <div className="px-6 pb-6 text-sm text-secondary leading-relaxed font-medium opacity-80">
                             {section.content}
                          </div>
                       </div>
                    </div>
                  ))}
               </div>
            </div>
          </div>
        </div>
      </div>

      {/* Mobile Sticky CTA */}
      <div className="lg:hidden fixed bottom-0 inset-x-0 bg-white/80 backdrop-blur-xl border-t border-border p-4 z-[100] flex gap-4 shadow-[0_-10px_40px_rgba(0,0,0,0.1)]">
         <div className="flex-1 flex flex-col justify-center px-2">
            <span className="text-[10px] font-black text-light line-through">Rs. {product.mrp}</span>
            <span className="text-lg font-black text-dark leading-none">Rs. {product.price}</span>
         </div>
         <button 
          onClick={handleAddToCart}
          className="flex-[2] btn-primary !rounded-2xl flex items-center justify-center space-x-3 py-4 shadow-xl active:scale-95 transition-all"
         >
           <ShoppingBag size={20} strokeWidth={3} />
           <span className="text-xs font-black tracking-widest uppercase">ADD TO BAG</span>
         </button>
      </div>
    </div>
  );
};

export default ProductDetails;

import React, { useState, useEffect } from 'react';
import { Link, useNavigate } from 'react-router-dom';
import { ShoppingBag, X, Heart, Star, ChevronRight, Share2, Sparkles, ShoppingCart } from 'lucide-react';
import { toast } from 'react-toastify';

const mockWishlist = [
  { _id: '1', name: 'Premium Heavyweight Cotton Tee', brand: 'LANDLO', image: 'https://images.unsplash.com/photo-1521572163474-6864f9cf17ab?auto=format&fit=crop&q=80&w=800', price: 1499, mrp: 2499, rating: 4.5, reviews: 120 },
  { _id: '2', name: 'Slim Fit Dark Wash Jeans', brand: 'LEVIS', image: 'https://images.unsplash.com/photo-1542272604-787c3835535d?auto=format&fit=crop&q=80&w=800', price: 2999, mrp: 3999, rating: 4.2, reviews: 85 },
];

const Wishlist = () => {
  const [items, setItems] = useState(mockWishlist);
  const navigate = useNavigate();
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    const timer = setTimeout(() => setLoading(false), 800);
    return () => clearTimeout(timer);
  }, []);

  const removeItem = (id) => {
    setItems(items.filter(item => item._id !== id));
    toast.info('Removed from favorites');
  };

  const moveToBag = (id) => {
    toast.success('Analyzing availability... Moved to bag!');
  };

  if (items.length === 0) {
    return (
      <div className="container mx-auto px-4 py-32 text-center min-h-[70vh] flex flex-col justify-center items-center">
        <div className="w-32 h-32 bg-surface rounded-full flex items-center justify-center mb-10 shadow-inner">
           <Heart size={56} className="text-light opacity-60" />
        </div>
        <h2 className="text-3xl font-black uppercase tracking-tighter mb-4 italic">Lonely Favorites</h2>
        <p className="text-secondary mb-12 max-w-sm mx-auto text-sm font-medium opacity-80 decoration-primary decoration-2">
          Your curated list is currently empty. <br className="hidden sm:block" /> Start exploring the latest drops to fill it up.
        </p>
        <Link to="/shop" className="btn-primary !rounded-full !px-16 !py-5 shadow-2xl hover:shadow-primary/40 active:scale-95 transition-all flex items-center space-x-3 group">
          <span className="font-black tracking-[0.2em] text-xs">EXPLORE COLLECTION</span>
          <ChevronRight size={18} className="group-hover:translate-x-1 transition-transform" />
        </Link>
      </div>
    );
  }

  return (
    <div className="bg-white min-h-screen py-10 lg:py-20">
      <div className="container mx-auto px-4 lg:px-20 max-w-7xl">
        
        <div className="flex flex-col md:flex-row md:items-end justify-between mb-16 lg:mb-24 gap-8">
           <div className="space-y-4">
              <div className="flex items-center space-x-3">
                 <Heart size={20} className="text-primary animate-pulse" fill="currentColor" />
                 <span className="text-[10px] font-black uppercase tracking-[0.4em] text-light">Curated Selection</span>
              </div>
              <h1 className="text-4xl lg:text-6xl font-black uppercase tracking-tighter text-dark leading-none italic">
                 My Favorites <span className="text-secondary opacity-30 italic font-medium ml-2">- {items.length} items</span>
              </h1>
           </div>
           
           <div className="flex items-center space-x-6">
              <button className="p-3 bg-surface hover:bg-dark hover:text-white rounded-full transition-all group active:scale-90">
                 <Share2 size={20} className="group-hover:scale-110" />
              </button>
              <Link to="/cart" className="flex items-center space-x-4 bg-dark text-white px-8 py-4 rounded-full font-black text-[10px] uppercase tracking-[0.2em] hover:bg-primary transition-all shadow-xl active:scale-95 group">
                 <ShoppingCart size={16} className="group-hover:rotate-12 transition-transform" />
                 <span>GO TO BAG</span>
              </Link>
           </div>
        </div>

        <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 xl:grid-cols-4 gap-12 lg:gap-16">
          {items.map((product) => (
            <div key={product._id} className="group relative transition-all duration-700">
              
              {/* Product Card Container */}
              <div className="relative aspect-[3/4] bg-surface rounded-[2rem] overflow-hidden shadow-lg group-hover:shadow-[0_40px_80px_rgba(0,0,0,0.15)] group-hover:-translate-y-4 transition-all duration-700">
                <Link to={`/product/${product._id}`} className="block w-full h-full">
                  <img 
                    src={product.image} 
                    alt={product.name} 
                    className="w-full h-full object-cover group-hover:scale-110 transition-transform duration-1000 ease-out" 
                  />
                  
                  {/* Overlay Gradient */}
                  <div className="absolute inset-0 bg-gradient-to-t from-black/60 via-transparent to-transparent opacity-0 group-hover:opacity-100 transition-opacity duration-700"></div>
                </Link>
                
                {/* Remove Icon */}
                <button 
                  onClick={() => removeItem(product._id)}
                  className="absolute top-6 right-6 p-4 bg-white/80 backdrop-blur-xl shadow-2xl rounded-2xl text-secondary hover:text-red-500 transition-all z-10 active:scale-75 group/remove"
                >
                  <X size={18} className="group-hover/remove:rotate-90 transition-transform" />
                </button>

                {/* Rating Badge */}
                <div className="absolute top-6 left-6 flex items-center bg-dark text-white px-3 py-1.5 rounded-xl text-[10px] font-black border border-white/10 shadow-2xl">
                   {product.rating} <Star size={10} fill="currentColor" className="ml-1.5 text-primary" />
                </div>

                {/* Quick Add Button - Desktop Only */}
                <div className="absolute bottom-8 inset-x-8 translate-y-20 opacity-0 group-hover:translate-y-0 group-hover:opacity-100 transition-all duration-700">
                   <button 
                     onClick={() => moveToBag(product._id)}
                     className="w-full py-4 bg-white text-dark rounded-2xl font-black text-[10px] uppercase tracking-[0.2em] flex items-center justify-center space-x-3 hover:bg-primary hover:text-white transition-all shadow-2xl active:scale-95"
                   >
                     <ShoppingBag size={14} strokeWidth={3} />
                     <span>ADD TO BAG</span>
                   </button>
                </div>
              </div>

              {/* Product Info */}
              <div className="mt-8 px-2 space-y-3">
                <div className="flex justify-between items-start">
                   <div className="space-y-1">
                      <h3 className="text-[10px] font-black uppercase text-secondary tracking-[0.3em] flex items-center">
                         {product.brand} <Sparkles size={10} className="ml-2 text-primary opacity-40" />
                      </h3>
                      <p className="text-lg text-dark font-black tracking-tighter uppercase leading-tight line-clamp-1">{product.name}</p>
                   </div>
                </div>
                
                <div className="flex items-center space-x-4">
                  <span className="text-xl font-black text-dark tracking-tighter">Rs. {product.price}</span>
                  <span className="text-sm text-light line-through font-medium opacity-60">Rs. {product.mrp}</span>
                  <span className="text-[10px] bg-primary/10 text-primary px-3 py-1 rounded-full font-black uppercase tracking-widest">{Math.round(((product.mrp - product.price) / product.mrp) * 100)}% OFF</span>
                </div>

                <div className="md:hidden pt-4">
                   <button 
                     onClick={() => moveToBag(product._id)}
                     className="w-full py-3.5 bg-surface border-2 border-transparent hover:border-dark text-dark rounded-2xl font-black text-[10px] uppercase tracking-[0.2em] flex items-center justify-center space-x-3 transition-all active:scale-95"
                   >
                     <ShoppingBag size={14} strokeWidth={3} />
                     <span>MOVE TO BAG</span>
                   </button>
                </div>
              </div>

            </div>
          ))}
        </div>

      </div>
    </div>
  );
};

