import React, { useState, useEffect } from 'react';
import { useNavigate, useParams } from 'react-router-dom';
import { Upload, X, ArrowLeft, Loader2 } from 'lucide-react';
import { toast } from 'react-toastify';
import api from '../../services/api';

const EditProduct = () => {
  const { id } = useParams();
  const navigate = useNavigate();
  const [images, setImages] = useState([]);
  const [loading, setLoading] = useState(true);
  const [saving, setSaving] = useState(false);
  
  const [formData, setFormData] = useState({
    name: '',
    category: '',
    price: '',
    stock: '',
    description: '',
    sizes: [],
    colors: []
  });

  const availableSizes = ['XS', 'S', 'M', 'L', 'XL', 'XXL'];
  const availableColors = ['Black', 'White', 'Navy', 'Olive', 'Red', 'Sand'];

  useEffect(() => {
    fetchProduct();
  }, [id]);

  const fetchProduct = async () => {
    try {
      const { data } = await api.get(`/products/${id}`);
      setFormData({
        name: data.name || '',
        category: data.category || '',
        price: data.price || '',
        stock: data.countInStock || 0,
        description: data.description || '',
        sizes: data.sizes || [],
        colors: data.colors || []
      });
      if (data.image) {
        setImages([data.image]); // Simplified to handle single image from schema
      }
    } catch (error) {
      toast.error('Failed to fetch product details');
      navigate('/admin/products');
    } finally {
      setLoading(false);
    }
  };

  const handleImageUpload = (e) => {
    const files = Array.from(e.target.files);
    const newImages = files.map(file => URL.createObjectURL(file));
    setImages(prev => [...prev, ...newImages]);
  };

  const removeImage = (index) => {
    setImages(prev => prev.filter((_, i) => i !== index));
  };

  const handleChange = (e) => {
    const { name, value } = e.target;
    setFormData(prev => ({ ...prev, [name]: value }));
  };

  const toggleArrayItem = (field, item) => {
    setFormData(prev => {
      const array = prev[field];
      if (array.includes(item)) {
        return { ...prev, [field]: array.filter(i => i !== item) };
      } else {
        return { ...prev, [field]: [...array, item] };
      }
    });
  };

  const handleSubmit = async (e) => {
    e.preventDefault();
    
    const payload = {
      name: formData.name,
      price: Number(formData.price),
      category: formData.category,
      brand: 'LANDLO', 
      countInStock: Number(formData.stock),
      description: formData.description,
      sizes: formData.sizes,
      colors: formData.colors,
      image: images.length > 0 ? images[0] : '/placeholder.jpg' 
    };

    try {
      setSaving(true);
      await api.put(`/products/${id}`, payload);
      toast.success('Product updated successfully!');
      navigate('/admin/products');
    } catch (error) {
      toast.error(error.response?.data?.message || 'Failed to update product');
    } finally {
      setSaving(false);
    }
  };

  if (loading) {
    return (
      <div className="flex justify-center items-center h-64">
        <Loader2 className="animate-spin text-gray-500" size={40} />
      </div>
    );
  }

  return (
    <div className="max-w-4xl mx-auto space-y-6 pb-20">
      <div className="flex items-center space-x-4 mb-8">
        <button 
          onClick={() => navigate('/admin/products')}
          className="p-2 hover:bg-gray-100 rounded-full transition-colors"
        >
          <ArrowLeft size={20} />
        </button>
        <div>
          <h2 className="text-2xl font-bold font-heading">Edit Product</h2>
          <p className="text-gray-500 text-sm">Update product information and inventory.</p>
        </div>
      </div>

      <form onSubmit={handleSubmit} className="space-y-8">
        
        {/* Basic Info */}
        <div className="bg-white p-6 rounded-lg border border-gray-100 shadow-sm space-y-6">
          <h3 className="text-lg font-heading font-bold border-b border-gray-100 pb-4">Basic Information</h3>
          
          <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
            <div className="space-y-2">
              <label className="text-sm font-medium text-gray-700">Product Name *</label>
              <input 
                type="text" 
                name="name"
                required
                value={formData.name}
                onChange={handleChange}
                className="w-full border border-gray-300 rounded-md px-4 py-2.5 focus:outline-none focus:ring-2 focus:ring-black"
              />
            </div>
            <div className="space-y-2">
              <label className="text-sm font-medium text-gray-700">Category *</label>
              <select
                name="category"
                required
                value={formData.category}
                onChange={handleChange}
                className="w-full border border-gray-300 rounded-md px-4 py-2.5 focus:outline-none focus:ring-2 focus:ring-black appearance-none"
              >
                <option value="">Select Category</option>
                <option value="Men">Men</option>
                <option value="Women">Women</option>
                <option value="Kids">Kids</option>
                <option value="Accessories">Accessories</option>
              </select>
            </div>
            <div className="space-y-2">
              <label className="text-sm font-medium text-gray-700">Price ($) *</label>
              <input 
                type="number" 
                name="price"
                required
                min="0"
                step="0.01"
                value={formData.price}
                onChange={handleChange}
                className="w-full border border-gray-300 rounded-md px-4 py-2.5 focus:outline-none focus:ring-2 focus:ring-black"
              />
            </div>
            <div className="space-y-2">
              <label className="text-sm font-medium text-gray-700">Stock Quantity *</label>
              <input 
                type="number" 
                name="stock"
                required
                min="0"
                value={formData.stock}
                onChange={handleChange}
                className="w-full border border-gray-300 rounded-md px-4 py-2.5 focus:outline-none focus:ring-2 focus:ring-black"
              />
            </div>
          </div>

          <div className="space-y-2">
            <label className="text-sm font-medium text-gray-700">Description</label>
            <textarea 
              name="description"
              rows={4}
              value={formData.description}
              onChange={handleChange}
              className="w-full border border-gray-300 rounded-md px-4 py-2.5 focus:outline-none focus:ring-2 focus:ring-black resize-none"
            ></textarea>
          </div>
        </div>

        {/* Media */}
        <div className="bg-white p-6 rounded-lg border border-gray-100 shadow-sm space-y-6">
          <h3 className="text-lg font-heading font-bold border-b border-gray-100 pb-4">Product Media</h3>
          
          <div className="grid grid-cols-2 md:grid-cols-4 lg:grid-cols-5 gap-4">
            {images.map((img, index) => (
              <div key={index} className="relative aspect-square border-2 border-gray-200 rounded-lg overflow-hidden group">
                <img src={img} alt={`Preview ${index}`} className="w-full h-full object-cover" />
                <button 
                  type="button"
                  onClick={() => removeImage(index)}
                  className="absolute top-2 right-2 bg-red-500 text-white rounded-full p-1 opacity-0 group-hover:opacity-100 transition-opacity"
                >
                  <X size={16} />
                </button>
              </div>
            ))}
            
            <label className="aspect-square border-2 border-dashed border-gray-300 rounded-lg flex flex-col items-center justify-center cursor-pointer hover:bg-gray-50 transition-colors text-gray-500 hover:text-black">
              <Upload size={24} className="mb-2" />
              <span className="text-xs font-medium">Upload Image</span>
              <input 
                type="file" 
                multiple 
                accept="image/jpeg, image/png, image/webp"
                className="hidden" 
                onChange={handleImageUpload}
              />
            </label>
          </div>
        </div>

        {/* Variants */}
        <div className="bg-white p-6 rounded-lg border border-gray-100 shadow-sm space-y-6">
          <h3 className="text-lg font-heading font-bold border-b border-gray-100 pb-4">Variants & Options</h3>
          
          <div className="space-y-6">
            <div className="space-y-3">
              <label className="text-sm font-medium text-gray-700">Available Sizes</label>
              <div className="flex flex-wrap gap-3">
                {availableSizes.map(size => (
                  <button
                    type="button"
                    key={size}
                    onClick={() => toggleArrayItem('sizes', size)}
                    className={`w-12 h-12 rounded border flex items-center justify-center text-sm font-medium transition-all ${
                      formData.sizes.includes(size) 
                        ? 'border-black bg-black text-white' 
                        : 'border-gray-200 text-gray-600 hover:border-black'
                    }`}
                  >
                    {size}
                  </button>
                ))}
              </div>
            </div>

            <div className="space-y-3">
              <label className="text-sm font-medium text-gray-700">Available Colors</label>
              <div className="flex flex-wrap gap-3">
                {availableColors.map(color => (
                  <button
                    type="button"
                    key={color}
                    onClick={() => toggleArrayItem('colors', color)}
                    className={`px-4 py-2 rounded-full border text-sm font-medium transition-all ${
                      formData.colors.includes(color) 
                        ? 'border-black bg-black text-white' 
                        : 'border-gray-200 text-gray-600 hover:border-black'
                    }`}
                  >
                    {color}
                  </button>
                ))}
              </div>
            </div>
          </div>
        </div>

        {/* Form Actions */}
        <div className="flex justify-end space-x-4 pt-4">
          <button 
            type="button"
            onClick={() => navigate('/admin/products')}
            className="px-6 py-3 border border-gray-300 rounded-md text-gray-700 font-bold hover:bg-gray-50 transition-colors"
          >
            Cancel
          </button>
          <button 
            type="submit"
            disabled={saving}
            className="btn-primary px-8 flex items-center justify-center min-w-[160px]"
          >
            {saving ? <Loader2 className="animate-spin" size={20} /> : 'Update Product'}
          </button>
        </div>

      </form>
    </div>
  );
};

export default EditProduct;
